import React, { useState, useEffect } from 'react';
import api from '../api/api';
import { Line } from 'react-chartjs-2'; 
import { Chart as ChartJS, CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend } from 'chart.js';

// Register Chart.js components
ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend);


const ProgressChart = ({ dailyCalorieTarget }) => {
    const [chartData, setChartData] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    // Map risk score value to text for the y2 axis labels
    const riskTextMap = { 1: 'Low', 2: 'Medium', 3: 'High' };

    useEffect(() => {
        const fetchData = async () => {
            if (!dailyCalorieTarget) {
                 setError("Calorie Target not set. Please update your Profile.");
                 setLoading(false);
                 return;
            }
            try {
                const response = await api.get('/analytics/progress');
                const data = response.data;

                // 1. Prepare Labels (Dates)
                const dates = [...new Set([
                    ...data.weightHistory.map(d => d.date),
                    ...data.calorieHistory.map(d => d.date)
                ])].sort();

                // 2. Map data to dates (fill missing dates with null for Chart.js)
                const weightMap = new Map(data.weightHistory.map(item => [item.date, item.weight]));
                const calorieMap = new Map(data.calorieHistory.map(item => [item.date, item.calories]));
                const riskMap = new Map(data.riskHistory.map(item => [item.date, item.score])); 
                

                setChartData({
                    labels: dates,
                    datasets: [
                        // Primary Line: Weight History (Electric Blue - Primary Accent)
                        {
                            label: 'Weight (kg)',
                            data: dates.map(date => weightMap.get(date) || null),
                            borderColor: '#00AEEF', // AI Blue
                            yAxisID: 'y',
                            tension: 0.2,
                            pointBackgroundColor: '#00AEEF',
                            spanGaps: true,
                        },
                        // Secondary Line: Calorie Intake (High Contrast Red)
                        {
                            label: 'Calorie Intake (kcal)',
                            data: dates.map(date => calorieMap.get(date) || null),
                            borderColor: '#FF4C4C', // Bright Red
                            backgroundColor: 'rgba(255, 76, 76, 0.2)',
                            yAxisID: 'y1',
                            spanGaps: true,
                        },
                        // Target Line (Horizontal - Neon Green/Cyan)
                        {
                            label: 'Calorie Target',
                            data: dates.map(() => data.target),
                            borderColor: '#00FFC0', // AI Green Target
                            borderDash: [8, 8], // Dashed line
                            pointRadius: 0,
                            yAxisID: 'y1',
                            tension: 0,
                        },
                        // Overlay Dataset: Health Risk Score (Visual Only)
                        {
                            label: 'Risk Score Overlay (1=Low, 3=High)',
                            data: dates.map(date => riskMap.get(date) || null),
                            borderColor: 'transparent',
                            backgroundColor: 'rgba(255, 180, 0, 0.8)', // Orange/Gold
                            yAxisID: 'y2', 
                            showLine: false, 
                            pointStyle: dates.map(date => riskMap.get(date) === 3 ? 'triangle' : riskMap.get(date) === 2 ? 'rect' : 'circle'),
                            pointRadius: 8
                        }
                    ],
                });
                setLoading(false);

            } catch (err) {
                console.error("Analytics fetch failed:", err);
                if (err.response && err.response.status === 401) {
                    setError("Unauthorized. Please log in again.");
                } else {
                    setError("Failed to load historical data. Check backend logs.");
                }
                setLoading(false);
            }
        };

        fetchData();
    }, [dailyCalorieTarget]); 

    // Chart Options (Configuring multiple Y-axes for Dark Theme)
    const options = {
        responsive: true,
        maintainAspectRatio: false,
        interaction: { mode: 'index', intersect: false },
        stacked: false,
        plugins: {
            legend: { 
                position: 'top',
                labels: {
                    color: '#C9D1D9', // Legend text color
                }
            },
            title: { 
                display: true, 
                text: 'Progress Tracker & Risk Correlation',
                color: '#00FFC0', // Chart title color
                font: { size: 18 }
            },
            tooltip: {
                backgroundColor: 'rgba(22, 27, 34, 0.85)', // Dark tooltip background
                titleColor: '#FFFFFF',
                bodyColor: '#C9D1D9',
                borderColor: '#00AEEF',
                borderWidth: 1
            }
        },
        scales: {
            x: { // X-axis (Dates)
                ticks: { color: '#C9D1D9' },
                grid: { color: 'rgba(45, 51, 59, 0.5)' } // Dark, subtle grid lines
            },
            y: { // Y-axis for Weight
                type: 'linear',
                display: true,
                position: 'left',
                title: { display: true, text: 'Weight (kg)', color: '#C9D1D9' },
                ticks: { color: '#C9D1D9' },
                grid: { color: 'rgba(45, 51, 59, 0.5)' },
                min: 50, max: 120,
            },
            y1: { // Y1-axis for Calorie Intake/Target
                type: 'linear',
                display: true,
                position: 'right',
                title: { display: true, text: 'Calorie Intake (kcal)', color: '#C9D1D9' },
                ticks: { color: '#C9D1D9' },
                min: 1000, max: 4000,
                grid: { drawOnChartArea: false },
            },
            y2: { // Y2-axis for Risk Score Overlay
                type: 'linear',
                display: true,
                position: 'left',
                title: { display: true, text: 'Risk Score', color: '#C9D1D9' },
                ticks: {
                    color: '#C9D1D9',
                    stepSize: 1,
                    callback: function(value) {
                        return riskTextMap[value] || ''; // Shows Low, Medium, High text labels
                    }
                },
                grid: { drawOnChartArea: false },
                min: 0.5, max: 3.5,
            }
        }
    };


    if (loading) return <div className="text-center py-10 text-gray-500">Loading charts...</div>;
    if (error) return <div className="text-center py-10 text-red-500">{error}</div>;

    return (
        <div style={{ height: '500px' }}> {/* Container for fixed chart height */}
            {chartData && chartData.labels.length > 0 ? (
                <Line options={options} data={chartData} />
            ) : (
                <div className="text-center py-10 text-gray-500 border border-dashed border-gray-700 p-8 mt-10 rounded-lg">
                    No Historical Data. Log a meal or complete a risk check to start tracking progress!
                </div>
            )}
        </div>
    );
};

export default ProgressChart;
